def format_re_for_filename(re_value):
    """Convert Reynolds number to filename format"""
    if re_value >= 1000000:
        return f"{re_value // 1000000}e6"
    elif re_value >= 1000:
        return f"{re_value // 1000}k"
    return str(re_value)


def download_polar(url, output_path):
    """Download polar text from URL"""
    try:
        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
        with urllib.request.urlopen(req) as response:
            content = response.read().decode('utf-8')
            # Ensure directory exists
            os.makedirs(os.path.dirname(output_path), exist_ok=True)
            with open(output_path, 'w', encoding='utf-8') as f:
                f.write(content)
        return True
    except Exception as e:
        print(f"  ERROR downloading: {e}")
        return False


def convert_polar(job):
    """Convert downloaded polar using TypeScript converter"""
    # First download the polar text to a temp file
    temp_txt = f"temp_polar_{job['airfoil']}_{job['re']}.txt"
    
    print(f"  Downloading {job['airfoil']} Re={job['re']}...")
    if not download_polar(job['src'], temp_txt):
        return False
    
    # Call TypeScript converter
    cmd = [
        'npx', 'ts-node', 'scripts/convertAirfoilToolsPolar.ts',
        '--airfoil', job['airfoil'],
        '--re', str(job['re']),
        '--src', temp_txt,
        '--out', job['out'],
        '--mach', str(job['mach']),
        '--source', job['source'],
        '--notes', job['notes'],
    ]
    
    try:
        result = subprocess.run(cmd, capture_output=True, text=True, check=True)
        print(f"  ✓ Converted: {job['out']}")
        # Clean up temp file
        if os.path.exists(temp_txt):
            os.remove(temp_txt)
        return True
    except subprocess.CalledProcessError as e:
        print(f"  ERROR converting: {e}")
        print(f"    stdout: {e.stdout}")
        print(f"    stderr: {e.stderr}")
        # Clean up temp file even on error
        if os.path.exists(temp_txt):
            os.remove(temp_txt)
        return False


def main():
    print(f"Processing {len(JOBS)} polar generation jobs...\n")
    
    success_count = 0
    error_count = 0
    
    for i, job in enumerate(JOBS, 1):
        print(f"[{i}/{len(JOBS)}] {job['airfoil']} @ Re={job['re']}")
        
        if convert_polar(job):
            success_count += 1
        else:
            error_count += 1
        print()
    
    print(f"\n=== Summary ===")
    print(f"Success: {success_count}")
    print(f"Errors: {error_count}")
    print(f"Total: {len(JOBS)}")


if __name__ == '__main__':
    main()

